package com.ecommerce.model;
import jakarta.persistence.*;import lombok.*;import org.springframework.data.annotation.CreatedDate;import org.springframework.data.jpa.domain.support.AuditingEntityListener;import java.time.LocalDateTime;import java.util.*;
@Entity @Table(name="categories") @Data @Builder @NoArgsConstructor @AllArgsConstructor @EntityListeners(AuditingEntityListener.class)
public class Category { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false) private String name; @Column(unique=true,nullable=false) private String slug; @Column(columnDefinition="TEXT") private String description; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="parent_category_id") @ToString.Exclude @EqualsAndHashCode.Exclude private Category parentCategory; @OneToMany(mappedBy="parentCategory",fetch=FetchType.LAZY) @ToString.Exclude @EqualsAndHashCode.Exclude @Builder.Default private List<Category> subCategories=new ArrayList<>(); @OneToMany(mappedBy="category",fetch=FetchType.LAZY) @ToString.Exclude @EqualsAndHashCode.Exclude @Builder.Default private List<Product> products=new ArrayList<>(); @CreatedDate @Column(updatable=false) private LocalDateTime createdAt; }
